"use client";

import { Popover as PopoverPrimitive } from "@base-ui/react/popover";
import * as stylex from "@stylexjs/stylex";
import type React from "react";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { popoverStyles } from "./popover.styles";

export const PopoverCreateHandle: typeof PopoverPrimitive.createHandle =
	PopoverPrimitive.createHandle;

export function Popover(
	props: PopoverPrimitive.Root.Props,
): React.ReactElement {
	return <PopoverPrimitive.Root {...props} />;
}

export function PopoverTrigger(
	props: PopoverPrimitive.Trigger.Props,
): React.ReactElement {
	return <PopoverPrimitive.Trigger data-slot="popover-trigger" {...props} />;
}

export function PopoverClose(
	props: PopoverPrimitive.Close.Props,
): React.ReactElement {
	return <PopoverPrimitive.Close data-slot="popover-close" {...props} />;
}

export function PopoverPortal(
	props: PopoverPrimitive.Portal.Props,
): React.ReactElement {
	return <PopoverPrimitive.Portal {...props} />;
}

export function PopoverPositioner({
	sideOffset = 4,
	side = "bottom",
	align = "center",
	...props
}: PopoverPrimitive.Positioner.Props): React.ReactElement {
	return (
		<PopoverPrimitive.Positioner
			sideOffset={sideOffset}
			side={side}
			align={align}
			{...stylex.props(popoverStyles.positioner)}
			data-slot="popover-positioner"
			{...props}
		/>
	);
}

export function PopoverPopup({
	style,
	...props
}: PropsWithStylex<PopoverPrimitive.Popup.Props>): React.ReactElement {
	return (
		<PopoverPrimitive.Popup
			{...stylex.props(popoverStyles.popup, style)}
			data-slot="popover-popup"
			{...props}
		/>
	);
}

export function PopoverArrow(
	props: PopoverPrimitive.Arrow.Props,
): React.ReactElement {
	return (
		<PopoverPrimitive.Arrow
			{...stylex.props(popoverStyles.arrow)}
			data-slot="popover-arrow"
			{...props}
		>
			<div {...stylex.props(popoverStyles.arrowFill)} />
		</PopoverPrimitive.Arrow>
	);
}

export function PopoverBackdrop(
	props: PopoverPrimitive.Backdrop.Props,
): React.ReactElement {
	return (
		<PopoverPrimitive.Backdrop
			{...stylex.props(popoverStyles.backdrop)}
			data-slot="popover-backdrop"
			{...props}
		/>
	);
}

export function PopoverTitle(
	props: PopoverPrimitive.Title.Props,
): React.ReactElement {
	return (
		<PopoverPrimitive.Title
			{...stylex.props(popoverStyles.title)}
			data-slot="popover-title"
			{...props}
		/>
	);
}

export function PopoverDescription(
	props: PopoverPrimitive.Description.Props,
): React.ReactElement {
	return (
		<PopoverPrimitive.Description
			{...stylex.props(popoverStyles.description)}
			data-slot="popover-description"
			{...props}
		/>
	);
}

export const PopoverRoot = Popover;

export const PopoverCompound = {
	Root: Popover,
	Trigger: PopoverTrigger,
	Close: PopoverClose,
	Portal: PopoverPortal,
	Positioner: PopoverPositioner,
	Popup: PopoverPopup,
	Arrow: PopoverArrow,
	Backdrop: PopoverBackdrop,
	Title: PopoverTitle,
	Description: PopoverDescription,
	createHandle: PopoverCreateHandle,
};

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	borderWidth,
	fontSize,
	fontWeight,
	spacing,
} from "@/lib/theme/tokens.stylex";

export const popoverStyles = stylex.create({
	backdrop: {
		position: "fixed",
		inset: 0,
		zIndex: 50,
		backgroundColor: "rgba(0, 0, 0, 0.32)",
	},
	positioner: {
		zIndex: 50,
		outline: "none",
	},
	popup: {
		boxSizing: "border-box",
		minWidth: 160,
		// --anchor-width is a CSS variable set by the PopoverPositioner component
		width: "max(var(--anchor-width), 240px)",
		maxWidth: "calc(100vw - 16px)",
		padding: spacing.small,
		backgroundColor: theme.surface,
		borderWidth: borderWidth.thin,
		borderStyle: "solid",
		borderColor: theme.border,
		borderRadius: borderRadius.large,
		boxShadow: theme.shadowLg,
		outline: "none",
		transformOrigin: "var(--transform-origin)",
		transitionProperty: {
			default: "opacity, scale",
			"@media (prefers-reduced-motion: reduce)": "none",
		},
		transitionDuration: {
			default: "150ms",
			"@media (prefers-reduced-motion: reduce)": "0ms",
		},
		transitionTimingFunction: "ease",
		"[data-starting-style]": {
			opacity: 0,
			scale: 0.95,
		},
		"[data-ending-style]": {
			opacity: 0,
			scale: 0.95,
		},
	},
	arrow: {
		position: "absolute",
		width: 10,
		height: 10,
	},
	arrowFill: {
		width: "100%",
		height: "100%",
		backgroundColor: theme.surface,
		borderWidth: borderWidth.thin,
		borderStyle: "solid",
		borderColor: theme.border,
		borderRadius: 2,
		transform: "rotate(45deg)",
	},
	title: {
		fontSize: fontSize.medium,
		fontWeight: fontWeight.semibold,
		color: theme.contentPrimary,
		margin: 0,
		paddingBottom: spacing.xsmall,
	},
	description: {
		fontSize: fontSize.small,
		color: theme.contentSecondary,
		margin: 0,
		paddingBottom: spacing.xsmall,
	},
});
